query:
SELECT COUNT(*) as total FROM equipment;
SELECT e.id, e.name, e.brand, e.model, e.serial_number, e.license_plate, e.status, e.sector_id, et.name as type_name 
FROM equipment e 
LEFT JOIN equipment_types et ON e.type_id = et.id 
ORDER BY e.id;

